import{f as T,D as o,o as e,c as h,a2 as r,b as n,w as a,a as d,G as s,a5 as i}from"./chunks/framework.DHYrF-q6.js";const g=JSON.parse('{"title":"HTTP 协议演进","description":"","frontmatter":{},"headers":[],"relativePath":"computer-network/application/http.md","filePath":"computer-network/application/http.md","lastUpdated":1780924599000}'),p={name:"computer-network/application/http.md"};function P(E,t,c,u,H,b){const l=o("Mermaid");return e(),h("div",null,[t[3]||(t[3]=r('<h1 id="http-协议演进" tabindex="-1">HTTP 协议演进 <a class="header-anchor" href="#http-协议演进" aria-label="Permalink to &quot;HTTP 协议演进&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>考察点</th><th>重要程度</th><th>面试频率</th><th>掌握目标</th></tr></thead><tbody><tr><td>HTTP/1.0 → 1.1 变化</td><td>⭐⭐⭐</td><td>极高</td><td>长连接、管线化、Host 头</td></tr><tr><td>HTTP/1.1 队头阻塞</td><td>⭐⭐⭐</td><td>极高</td><td>理解原因和影响</td></tr><tr><td>HTTP/2 多路复用</td><td>⭐⭐⭐</td><td>极高</td><td>二进制分帧、stream、优先级</td></tr><tr><td>HTTP/2 头部压缩</td><td>⭐⭐⭐</td><td>高</td><td>理解 HPACK 原理</td></tr><tr><td>HTTP/3 与 QUIC</td><td>⭐⭐⭐</td><td>极高</td><td>底层改用 UDP、解决队头阻塞</td></tr><tr><td>HTTP 无状态</td><td>⭐⭐</td><td>高</td><td>Cookie/Session/Token</td></tr></tbody></table><hr><h2 id="一、http-协议是什么" tabindex="-1">一、HTTP 协议是什么 <a class="header-anchor" href="#一、http-协议是什么" aria-label="Permalink to &quot;一、HTTP 协议是什么&quot;">​</a></h2><p>HTTP（HyperText Transfer Protocol，超文本传输协议）是应用层无状态协议，建立在 TCP 之上，遵循请求-响应模型。</p><p>核心特性：</p><table tabindex="0"><thead><tr><th>特性</th><th>说明</th></tr></thead><tbody><tr><td>无状态</td><td>服务器不保存客户端状态，每个请求都是独立的</td></tr><tr><td>请求-响应</td><td>客户端发送请求，服务器返回响应</td></tr><tr><td>基于 TCP</td><td>可靠传输，但存在队头阻塞问题</td></tr><tr><td>可扩展</td><td>通过首部字段扩展功能</td></tr></tbody></table><hr><h2 id="二、http-0-9-1991-最简原型" tabindex="-1">二、HTTP/0.9 (1991) -- 最简原型 <a class="header-anchor" href="#二、http-0-9-1991-最简原型" aria-label="Permalink to &quot;二、HTTP/0.9 (1991) -- 最简原型&quot;">​</a></h2><p>HTTP 的第一个版本，非常简陋：</p><ul><li>只支持 GET 方法</li><li>没有请求头和响应头</li><li>服务器只能返回 HTML 字符串</li><li>响应完成后立即关闭 TCP 连接</li></ul><p>请求示例：<code>GET /index.html</code></p><p>这就是 HTTP 的雏形，但现在已经见不到了。</p><hr><h2 id="三、http-1-0-1996-架构建立" tabindex="-1">三、HTTP/1.0 (1996) -- 架构建立 <a class="header-anchor" href="#三、http-1-0-1996-架构建立" aria-label="Permalink to &quot;三、HTTP/1.0 (1996) -- 架构建立&quot;">​</a></h2><p>HTTP/1.0 引入了现代 HTTP 的核心概念：</p><table tabindex="0"><thead><tr><th>新增特性</th><th>说明</th></tr></thead><tbody><tr><td>请求头和响应头</td><td>可以传递元信息（Content-Type、User-Agent 等）</td></tr><tr><td>状态码</td><td>即 200、404、500 等</td></tr><tr><td>POST/HEAD 方法</td><td>不只是 GET 了</td></tr><tr><td>多内容类型</td><td>不仅是 HTML，可以传输图片、视频、JSON 等</td></tr></tbody></table><p><strong>核心问题：短连接</strong></p><p>HTTP/1.0 默认每个请求建立一次 TCP 连接，响应完成后立即关闭。如果页面需要加载多个资源（CSS、JS、图片），每个资源都要重新三次握手，性能很差。</p><hr><h2 id="四、http-1-1-1997-经典版本" tabindex="-1">四、HTTP/1.1 (1997) -- 经典版本 <a class="header-anchor" href="#四、http-1-1-1997-经典版本" aria-label="Permalink to &quot;四、HTTP/1.1 (1997) -- 经典版本&quot;">​</a></h2><p>HTTP/1.1 是目前使用最广泛的 HTTP 版本，核心改进：</p><h3 id="_4-1-长连接-keep-alive" tabindex="-1">4.1 长连接（Keep-Alive） <a class="header-anchor" href="#_4-1-长连接-keep-alive" aria-label="Permalink to &quot;4.1 长连接（Keep-Alive）&quot;">​</a></h3><p>HTTP/1.1 默认开启长连接（<code>Connection: keep-alive</code>），一个 TCP 连接可以发送多个 HTTP 请求和响应，连接不会立即关闭，可以被复用。</p>',25)),(e(),n(i,null,{default:a(()=>[s(l,{id:"mermaid-273",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20C%20as%20%E5%AE%A2%E6%88%B7%E7%AB%AF%0A%20%20%20%20participant%20S%20as%20%E6%9C%8D%E5%8A%A1%E5%99%A8%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E4%B8%89%E6%AC%A1%E6%8F%A1%E6%89%8B%E5%BB%BA%E7%AB%8B%20TCP%20%E8%BF%9E%E6%8E%A5%0A%20%20%20%20C-%3E%3ES%3A%20HTTP%20%E8%AF%B7%E6%B1%82%201%0A%20%20%20%20S-%3E%3EC%3A%20HTTP%20%E5%93%8D%E5%BA%94%201%0A%20%20%20%20C-%3E%3ES%3A%20HTTP%20%E8%AF%B7%E6%B1%82%202%0A%20%20%20%20S-%3E%3EC%3A%20HTTP%20%E5%93%8D%E5%BA%94%202%0A%20%20%20%20C-%3E%3ES%3A%20HTTP%20%E8%AF%B7%E6%B1%82%203%0A%20%20%20%20S-%3E%3EC%3A%20HTTP%20%E5%93%8D%E5%BA%94%203%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E8%BF%9E%E6%8E%A5%E4%BF%9D%E6%8C%81%EF%BC%8C%E7%9B%B4%E5%88%B0%E4%B8%80%E6%96%B9%E5%85%B3%E9%97%AD%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[d(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r('<h3 id="_4-2-管线化-pipelining" tabindex="-1">4.2 管线化（Pipelining） <a class="header-anchor" href="#_4-2-管线化-pipelining" aria-label="Permalink to &quot;4.2 管线化（Pipelining）&quot;">​</a></h3><p>HTTP/1.1 支持管线化，客户端可以一口气发出多个请求，不用等上一个响应回来再发下一个。但服务器必须按照请求顺序返回响应。</p><div class="warning custom-block"><p class="custom-block-title">管线化的问题</p><p>管线化有一个关键缺陷：<strong>队头阻塞（Head-of-Line Blocking）</strong>。如果第一个请求处理很慢，后面的请求即使已经处理完也不能返回，必须等第一个返回才能继续。因此管线化在实际中很少被使用，大部分浏览器默认关闭。</p></div><h3 id="_4-3-host-头" tabindex="-1">4.3 Host 头 <a class="header-anchor" href="#_4-3-host-头" aria-label="Permalink to &quot;4.3 Host 头&quot;">​</a></h3><p>HTTP/1.1 要求必须包含 Host 头，指定域名。一台服务器可以托管多个域名（虚拟主机），服务器根据 Host 头区分请求是发给哪个站点的。</p><h3 id="_4-4-其他改进" tabindex="-1">4.4 其他改进 <a class="header-anchor" href="#_4-4-其他改进" aria-label="Permalink to &quot;4.4 其他改进&quot;">​</a></h3><ul><li>新增方法：PUT、DELETE、OPTIONS、TRACE、CONNECT</li><li>分块传输编码（Chunked Transfer Encoding）</li><li>断点续传（Range 请求）</li><li>缓存控制更精细（Cache-Control、ETag）</li></ul><hr><h2 id="五、http-2-2015-性能革命" tabindex="-1">五、HTTP/2 (2015) -- 性能革命 <a class="header-anchor" href="#五、http-2-2015-性能革命" aria-label="Permalink to &quot;五、HTTP/2 (2015) -- 性能革命&quot;">​</a></h2><p>HTTP/2 基于 Google 的 SPDY 协议，不以 HTTP/1.1 的文本格式为基础，而是全新的二进制协议。</p><h3 id="_5-1-二进制分帧" tabindex="-1">5.1 二进制分帧 <a class="header-anchor" href="#_5-1-二进制分帧" aria-label="Permalink to &quot;5.1 二进制分帧&quot;">​</a></h3><p>HTTP/2 不再使用文本协议，在应用层和传输层之间增加了一个<strong>二进制分帧层</strong>：</p><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td>帧（Frame）</td><td>最小通信单位，每个帧有类型（HEADERS、DATA、SETTINGS 等）</td></tr><tr><td>消息（Message）</td><td>一个完整的 HTTP 请求或响应，由多个帧组成</td></tr><tr><td>流（Stream）</td><td>一个双向字节流，承载一个或多个消息，在一条 TCP 连接上可以并发多个流</td></tr></tbody></table>',13)),(e(),n(i,null,{default:a(()=>[s(l,{id:"mermaid-367",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20subgraph%20%22HTTP%2F2%20%E8%BF%9E%E6%8E%A5%22%0A%20%20%20%20%20%20%20%20S1%5B%22Stream%201%3A%20%E8%AF%B7%E6%B1%82%20%2Findex.html%22%5D%0A%20%20%20%20%20%20%20%20S2%5B%22Stream%202%3A%20%E8%AF%B7%E6%B1%82%20%2Fstyle.css%22%5D%0A%20%20%20%20%20%20%20%20S3%5B%22Stream%203%3A%20%E8%AF%B7%E6%B1%82%20%2Fapp.js%22%5D%0A%20%20%20%20end%0A%20%20%20%20TC%5B%22%E5%8D%95%E4%B8%AA%20TCP%20%E8%BF%9E%E6%8E%A5%22%5D%0A%20%20%20%20S1%20--%3E%20TC%0A%20%20%20%20S2%20--%3E%20TC%0A%20%20%20%20S3%20--%3E%20TC%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[d(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=r(`<h3 id="_5-2-多路复用-multiplexing" tabindex="-1">5.2 多路复用（Multiplexing） <a class="header-anchor" href="#_5-2-多路复用-multiplexing" aria-label="Permalink to &quot;5.2 多路复用（Multiplexing）&quot;">​</a></h3><p>HTTP/2 的核心特性：一个 TCP 连接上可以同时发送多个请求，多个流之间互不阻塞。</p><p><strong>解决了 HTTP/1.1 的什么问题？</strong></p><p>HTTP/1.1 中，即使开了长连接，请求也是串行的（一个接一个）。管线化理论可以并发，但因为队头阻塞，实际使用效果很差。</p><p>HTTP/2 的多路复用真正做到：多个请求同时在一个 TCP 连接上传输，不需要排队。</p><div class="danger custom-block"><p class="custom-block-title">注意</p><p>HTTP/2 解决了 HTTP/1.1 的<strong>应用层队头阻塞</strong>，但<strong>TCP 层面的队头阻塞</strong>仍然存在：TCP 是字节流，如果一个 TCP 包丢了，整个 TCP 连接的所有流都会阻塞，等重传完才能继续。这是 HTTP/3 要解决的问题。</p></div><h3 id="_5-3-头部压缩-hpack" tabindex="-1">5.3 头部压缩（HPACK） <a class="header-anchor" href="#_5-3-头部压缩-hpack" aria-label="Permalink to &quot;5.3 头部压缩（HPACK）&quot;">​</a></h3><p>HTTP/1.1 中，每次请求都要带上完整的首部（Cookie、User-Agent 等），这些字段在连续请求中可能有大量重复。</p><p>HTTP/2 使用 HPACK 算法压缩头部：</p><ul><li>客户端和服务端各维护一份<strong>头部表</strong>（索引表）</li><li>已经发送过的头部字段，后续只需发送索引号</li><li>使用 Huffman 编码进一步压缩</li></ul><p>头部压缩可以节省大量带宽，尤其是 Cookie 很大的场景。</p><h3 id="_5-4-服务器推送-server-push" tabindex="-1">5.4 服务器推送（Server Push） <a class="header-anchor" href="#_5-4-服务器推送-server-push" aria-label="Permalink to &quot;5.4 服务器推送（Server Push）&quot;">​</a></h3><p>服务器可以主动向客户端推送资源。例如，客户端请求 index.html 后，服务器知道这个页面还需要 style.css 和 app.js，可以不等客户端请求就直接推送：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端请求 GET /index.html →</span></span>
<span class="line"><span>服务器响应 index.html +</span></span>
<span class="line"><span>  推送 /style.css +</span></span>
<span class="line"><span>  推送 /app.js</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">服务器推送的实际效果</p><p>服务器推送可以减少一次 RTT（客户端不需要先收到 HTML 再请求 CSS/JS），但在实际使用中，推送的资源可能已经被浏览器缓存，造成浪费。HTTP/3 中，服务器推送被移除了，改用 103 Early Hints 替代。</p></div><h3 id="_5-5-流优先级" tabindex="-1">5.5 流优先级 <a class="header-anchor" href="#_5-5-流优先级" aria-label="Permalink to &quot;5.5 流优先级&quot;">​</a></h3><p>HTTP/2 允许客户端设置流的优先级，服务器可以根据优先级决定先响应哪个流。例如，CSS 和 JS 的优先级高于图片。</p><hr><h2 id="六、http-3-2022-基于-quic" tabindex="-1">六、HTTP/3 (2022) -- 基于 QUIC <a class="header-anchor" href="#六、http-3-2022-基于-quic" aria-label="Permalink to &quot;六、HTTP/3 (2022) -- 基于 QUIC&quot;">​</a></h2><p>HTTP/3 是 HTTP 协议的最新版本，核心变化：<strong>底层传输协议从 TCP 换成了 QUIC（基于 UDP）</strong>。</p><h3 id="_6-1-为什么需要-http-3" tabindex="-1">6.1 为什么需要 HTTP/3？ <a class="header-anchor" href="#_6-1-为什么需要-http-3" aria-label="Permalink to &quot;6.1 为什么需要 HTTP/3？&quot;">​</a></h3><p>HTTP/2 解决了应用层队头阻塞，但 TCP 层面的队头阻塞仍然存在：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TCP 连接上多个 Stream 并发传输</span></span>
<span class="line"><span>    ↓ 某个 TCP 包丢失</span></span>
<span class="line"><span>TCP 重传该包 → 所有 Stream 都阻塞等待</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>HTTP/2 的多路复用优势被 TCP 队头阻塞抵消</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="_6-2-http-3-的核心改进" tabindex="-1">6.2 HTTP/3 的核心改进 <a class="header-anchor" href="#_6-2-http-3-的核心改进" aria-label="Permalink to &quot;6.2 HTTP/3 的核心改进&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>说明</th></tr></thead><tbody><tr><td>基于 QUIC</td><td>底层使用 UDP，不再用 TCP</td></tr><tr><td>0-RTT 握手</td><td>曾经连接过的客户端可以立即发送数据</td></tr><tr><td>彻底解决队头阻塞</td><td>每个流独立，一个流丢包不影响其他流</td></tr><tr><td>连接迁移</td><td>连接不依赖 IP 地址，WiFi 切 4G 不断开</td></tr><tr><td>内置加密</td><td>TLS 1.3 是 QUIC 的一部分，不是可选的</td></tr><tr><td>QPACK 头部压缩</td><td>改进的头部压缩方案，解决 HPACK 的队头阻塞</td></tr></tbody></table>`,25)),(e(),n(i,null,{default:a(()=>[s(l,{id:"mermaid-514",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20subgraph%20%22HTTP%2F1.1%22%0A%20%20%20%20%20%20%20%20A1%5B%22TCP%20%E8%BF%9E%E6%8E%A5%22%5D%20--%3E%20A2%5B%22%E8%AF%B7%E6%B1%821%20%E2%86%92%20%E5%93%8D%E5%BA%941%20%E2%86%92%20%E8%AF%B7%E6%B1%822%20%E2%86%92%20%E5%93%8D%E5%BA%942%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%22HTTP%2F2%22%0A%20%20%20%20%20%20%20%20B1%5B%22TCP%20%E8%BF%9E%E6%8E%A5%22%5D%20--%3E%20B2%5B%22Stream1%20%2B%20Stream2%20%E5%B9%B6%E5%8F%91%3Cbr%3E%E4%BD%86%20TCP%20%E4%B8%A2%E5%8C%85%E4%BB%8D%E9%98%BB%E5%A1%9E%E6%89%80%E6%9C%89%E6%B5%81%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%22HTTP%2F3%22%0A%20%20%20%20%20%20%20%20C1%5B%22QUIC%20%E8%BF%9E%E6%8E%A5%20(UDP)%22%5D%20--%3E%20C2%5B%22Stream1%20%2B%20Stream2%20%E7%8B%AC%E7%AB%8B%3Cbr%3E%E4%B8%80%E4%B8%AA%E4%B8%A2%E5%8C%85%E4%B8%8D%E5%BD%B1%E5%93%8D%E5%85%B6%E4%BB%96%E6%B5%81%22%5D%0A%20%20%20%20end%0A"})]),fallback:a(()=>[...t[2]||(t[2]=[d(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=r('<h3 id="_6-3-http-3-的现状" tabindex="-1">6.3 HTTP/3 的现状 <a class="header-anchor" href="#_6-3-http-3-的现状" aria-label="Permalink to &quot;6.3 HTTP/3 的现状&quot;">​</a></h3><ul><li>主流浏览器（Chrome、Firefox、Edge）均已支持 HTTP/3</li><li>主流 CDN（Cloudflare、Akamai）和云服务商均已支持</li><li>服务端：Nginx、Caddy、IIS 均已支持 HTTP/3</li><li>目前 HTTP/3 的普及率正在快速增长</li></ul><hr><h2 id="七、http-版本演进总结" tabindex="-1">七、HTTP 版本演进总结 <a class="header-anchor" href="#七、http-版本演进总结" aria-label="Permalink to &quot;七、HTTP 版本演进总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>年份</th><th>核心改进</th><th>传输层</th></tr></thead><tbody><tr><td>0.9</td><td>1991</td><td>仅 GET，只返回 HTML</td><td>TCP</td></tr><tr><td>1.0</td><td>1996</td><td>请求头/响应头、状态码、POST</td><td>TCP（短连接）</td></tr><tr><td>1.1</td><td>1997</td><td>长连接、管线化、Host 头</td><td>TCP（长连接）</td></tr><tr><td>2</td><td>2015</td><td>二进制分帧、多路复用、HPACK、Server Push</td><td>TCP</td></tr><tr><td>3</td><td>2022</td><td>基于 QUIC、0-RTT、彻底解决队头阻塞</td><td>QUIC（UDP）</td></tr></tbody></table><hr><h2 id="八、交叉关联到其他模块" tabindex="-1">八、交叉关联到其他模块 <a class="header-anchor" href="#八、交叉关联到其他模块" aria-label="Permalink to &quot;八、交叉关联到其他模块&quot;">​</a></h2><ul><li><strong>TCP 协议</strong>：参见 <a href="./../fundamentals/tcp">TCP 协议</a>，HTTP/1.1 和 HTTP/2 都是基于 TCP 的</li><li><strong>UDP 与 QUIC</strong>：参见 <a href="./../fundamentals/udp">UDP 协议</a>，HTTP/3 底层使用 QUIC（基于 UDP）</li><li><strong>HTTPS 与 TLS</strong>：参见 <a href="./https-tls">HTTPS 与 TLS</a>，HTTPS 是 HTTP + TLS 加密</li><li><strong>DNS 解析</strong>：参见 <a href="./dns">DNS 解析</a>，浏览器发出 HTTP 请求前的 DNS 解析过程</li><li><strong>WebSocket</strong>：参见 <a href="./websocket">WebSocket 协议</a>，WebSocket 通过 HTTP 升级建立全双工连接</li></ul><hr><h2 id="九、经典高频面试题" tabindex="-1">九、经典高频面试题 <a class="header-anchor" href="#九、经典高频面试题" aria-label="Permalink to &quot;九、经典高频面试题&quot;">​</a></h2><h3 id="q1-http-1-0-和-http-1-1-的主要区别是什么" tabindex="-1">Q1：HTTP/1.0 和 HTTP/1.1 的主要区别是什么？ <a class="header-anchor" href="#q1-http-1-0-和-http-1-1-的主要区别是什么" aria-label="Permalink to &quot;Q1：HTTP/1.0 和 HTTP/1.1 的主要区别是什么？&quot;">​</a></h3><p><strong>参考答案：</strong></p><ol><li><strong>长连接</strong>：HTTP/1.0 默认短连接，每次请求建立新连接；HTTP/1.1 默认长连接（Keep-Alive），一个连接可以复用多次请求</li><li><strong>Host 头</strong>：HTTP/1.1 必须包含 Host 头，支持虚拟主机</li><li><strong>管线化</strong>：HTTP/1.1 支持管线化，可以连续发送多个请求</li><li><strong>缓存控制</strong>：HTTP/1.1 引入了更精细的缓存控制（Cache-Control、ETag）</li><li><strong>新增方法</strong>：PUT、DELETE、OPTIONS、CONNECT、TRACE</li><li><strong>分块传输</strong>：HTTP/1.1 支持 Chunked Transfer Encoding</li><li><strong>断点续传</strong>：HTTP/1.1 支持 Range 请求</li></ol><h3 id="q2-http-2-相比-http-1-1-有哪些改进" tabindex="-1">Q2：HTTP/2 相比 HTTP/1.1 有哪些改进？ <a class="header-anchor" href="#q2-http-2-相比-http-1-1-有哪些改进" aria-label="Permalink to &quot;Q2：HTTP/2 相比 HTTP/1.1 有哪些改进？&quot;">​</a></h3><p><strong>参考答案：</strong></p><ol><li><strong>二进制分帧</strong>：不再使用文本协议，基于二进制帧，解析更高效</li><li><strong>多路复用</strong>：一个 TCP 连接可以并发多个请求/响应，解决 HTTP/1.1 的应用层队头阻塞</li><li><strong>头部压缩</strong>：HPACK 算法压缩请求/响应头，用索引表避免重复发送相同头部</li><li><strong>服务器推送</strong>：服务器可以主动推送资源给客户端</li><li><strong>流优先级</strong>：客户端可以设置请求优先级，服务器按优先级响应</li><li><strong>流量控制</strong>：基于流的流量控制，更精细</li></ol><h3 id="q3-http-2-的多路复用和-http-1-1-的管线化有什么区别" tabindex="-1">Q3：HTTP/2 的多路复用和 HTTP/1.1 的管线化有什么区别？ <a class="header-anchor" href="#q3-http-2-的多路复用和-http-1-1-的管线化有什么区别" aria-label="Permalink to &quot;Q3：HTTP/2 的多路复用和 HTTP/1.1 的管线化有什么区别？&quot;">​</a></h3><p><strong>参考答案：</strong> HTTP/1.1 管线化：</p><ul><li>可以连续发送多个请求，但响应必须按请求顺序返回</li><li>如果第一个请求处理慢，后面的响应被阻塞（队头阻塞）</li><li>实际中很少使用</li></ul><p>HTTP/2 多路复用：</p><ul><li>基于二进制帧和流，多个请求/响应可以交错传输</li><li>响应不需要按顺序返回，服务器处理完哪个先返回哪个</li><li>但 TCP 层面仍然存在队头阻塞（HTTP/3 解决）</li></ul><p>简单说：管线化是&quot;先进先出&quot;的队列，多路复用是&quot;谁先好谁先走&quot;的并行通道。</p><h3 id="q4-http-2-既然能多路复用-为什么还需要-http-3" tabindex="-1">Q4：HTTP/2 既然能多路复用，为什么还需要 HTTP/3？ <a class="header-anchor" href="#q4-http-2-既然能多路复用-为什么还需要-http-3" aria-label="Permalink to &quot;Q4：HTTP/2 既然能多路复用，为什么还需要 HTTP/3？&quot;">​</a></h3><p><strong>参考答案：</strong> HTTP/2 的多路复用解决了应用层的队头阻塞，但 TCP 层面的队头阻塞仍然存在：</p><p>TCP 是字节流，保证数据有序到达。如果 TCP 连接中有一个包丢失，后续所有包都不能被应用层处理，必须等重传完成。这意味着 HTTP/2 的所有流（Stream）都会被阻塞。</p><p>HTTP/3 底层使用 QUIC（基于 UDP），每个流独立传输，一个流丢包只影响该流，其他流不受影响。彻底解决了队头阻塞问题。</p><p>另外 HTTP/3 还提供了 0-RTT 握手、连接迁移等 TCP 无法实现的特性。</p><h3 id="q5-http-2-的头部压缩-hpack-是怎么工作的" tabindex="-1">Q5：HTTP/2 的头部压缩 HPACK 是怎么工作的？ <a class="header-anchor" href="#q5-http-2-的头部压缩-hpack-是怎么工作的" aria-label="Permalink to &quot;Q5：HTTP/2 的头部压缩 HPACK 是怎么工作的？&quot;">​</a></h3><p><strong>参考答案：</strong> HPACK 的核心原理：</p><ol><li><strong>静态表</strong>：预定义 61 个常用头部字段的索引（如 :method、:path、:status 等）</li><li><strong>动态表</strong>：客户端和服务端各自维护一个动态表，存储已发送的头部字段，后续发送时只需发送索引号</li><li><strong>Huffman 编码</strong>：对于不在表中的字段，使用 Huffman 编码进一步压缩</li></ol><p>例如，第一次请求发送 <code>:method: GET</code>，下次再请求时只需发送对应的索引号（2），而不是完整的字符串。</p><p>HPACK 的问题是：动态表依赖有序性，表更新必须按顺序处理，在 HTTP/3 中改用 QPACK，解决了这个问题。</p><h3 id="q6-http-3-为什么基于-udp-而不是-tcp" tabindex="-1">Q6：HTTP/3 为什么基于 UDP 而不是 TCP？ <a class="header-anchor" href="#q6-http-3-为什么基于-udp-而不是-tcp" aria-label="Permalink to &quot;Q6：HTTP/3 为什么基于 UDP 而不是 TCP？&quot;">​</a></h3><p><strong>参考答案：</strong></p><ol><li><strong>彻底解决队头阻塞</strong>：QUIC 在 UDP 之上实现了多流独立传输，一个流丢包不影响其他流</li><li><strong>协议僵化</strong>：TCP 在内核中实现，升级困难，QUIC 在用户态可快速迭代</li><li><strong>握手优化</strong>：QUIC 合并传输和加密握手，支持 0-RTT</li><li><strong>连接迁移</strong>：QUIC 通过 Connection ID 标识连接，切换网络不中断</li><li><strong>中间设备兼容</strong>：很多中间设备对 TCP 选项处理不一致，UDP 报文不受影响</li></ol>',35))])}const A=T(p,[["render",P]]);export{g as __pageData,A as default};
